1703→export async function getFocusedGraphView(input: {
1704→  surreal: Surreal;
1705→  workspaceRecord: RecordId<"workspace", string>;
1706→  centerEntityRecord: GraphEntityRecord;
1707→  depth: number;
1708→}): Promise<GraphViewRawResult> {
1709→  const clampedDepth = Math.max(1, Math.min(3, input.depth));
1710→
1711→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
1712→  if (!scoped) {
1713→    throw new Error("entity is outside the current workspace scope");
1714→  }
1715→
1716→  const collected = new Map<string, GraphEntityRecord>();
1717→  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);
1718→
1719→  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];
1720→
1721→  for (let hop = 0; hop < clampedDepth; hop++) {
1722→    if (frontier.length === 0) {
1723→      break;
1724→    }
1725→
1726→    const [rows] = await input.surreal
1727→      .query<[EntityRelationRow[]]>(
1728→        [
1729→          "SELECT id, `in`, out, kind, confidence",
1730→          "FROM entity_relation",
1731→          "WHERE `in` IN $currentIds OR out IN $currentIds;",
1732→        ].join(" "),
1733→        { currentIds: frontier },
1734→      )
1735→      .collect<[EntityRelationRow[]]>();
1736→
1737→    const nextFrontier: RecordId<string, string>[] = [];
1738→
1739→    for (const row of rows) {
1740→      for (const endpoint of [row.in, row.out]) {
1741→        const key = toRecordIdString(endpoint);
1742→        if (collected.has(key)) {
1743→          continue;
1744→        }
1745→
1746→        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint);
1747→        if (!inScope) {
1748→          continue;
1749→        }
1750→
1751→        collected.set(key, endpoint);
1752→        nextFrontier.push(endpoint);
1753→      }
1754→    }
1755→
1756→    frontier = nextFrontier;
1757→  }
1758→
1759→  const allRecords = Array.from(collected.values());
1760→  const entities = await resolveEntityNames(input.surreal, allRecords);
1761→  const edges = await collectEntityRelationEdges(input.surreal, allRecords);
1762→
1763→  return { entities, edges };
1764→}
