type EntityRelationRow = {
  id: RecordId<"entity_relation", string>;
  in: GraphEntityRecord;
  out: GraphEntityRecord;
  kind: string;
  confidence: number;
};

async function collectEntityRelationEdges(
  surreal: Surreal,
  entityIds: RecordId<string, string>[],
): Promise<GraphViewRawEdge[]> {
  if (entityIds.length === 0) {
    return [];
  }

  const edges: GraphViewRawEdge[] = [];

  // Generic entity_relation edges
  const [rows] = await surreal
    .query<[EntityRelationRow[]]>(
      [
        "SELECT id, `in`, out, kind, confidence",
        "FROM entity_relation",
        "WHERE `in` IN $entityIds AND out IN $entityIds;",
      ].join(" "),
      { entityIds },
    )
    .collect<[EntityRelationRow[]]>();

  for (const row of rows) {
    edges.push({
      id: toRecordIdString(row.id),
      fromId: toRecordIdString(row.in),
      toId: toRecordIdString(row.out),
      kind: row.kind,
      confidence: row.confidence,
    });
  }

  // Structural relation table edges
  const entityIdSet = new Set(entityIds.map((id) => toRecordIdString(id)));

  for (const table of STRUCTURAL_RELATION_TABLES) {
    const [structRows] = await surreal
      .query<[Array<{ id: RecordId<string, string>; in: RecordId<string, string>; out: RecordId<string, string> }>]>(
        `SELECT id, \`in\`, out FROM ${table} WHERE \`in\` IN $entityIds AND out IN $entityIds;`,
        { entityIds },
      )
      .collect<[Array<{ id: RecordId<string, string>; in: RecordId<string, string>; out: RecordId<string, string> }>]>();

    for (const row of structRows) {
      if (entityIdSet.has(toRecordIdString(row.in)) && entityIdSet.has(toRecordIdString(row.out))) {
        edges.push({
          id: toRecordIdString(row.id),
          fromId: toRecordIdString(row.in),
          toId: toRecordIdString(row.out),
          kind: table,
          confidence: 1.0,
        });
      }
    }
  }

  return edges;
}

